#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long n;
        if (scanf("%lld", &n) != 1) break;
        if (n % 2 == 0) {
            printf("true\n");
        } else {
            printf("false\n");
        }
    }
    return 0;
}

